# live_production_api
# Script Type: API
# API Method: live_production_api
# Supports live dashboard read + control actions for Job Cards.

args = frappe.form_dict
action = (args.get("action") or "get_data").strip().lower()


def to_float(v):
    try:
        return float(v or 0)
    except Exception:
        return 0.0


def to_datetime(v):
    if not v:
        return None
    try:
        return frappe.utils.get_datetime(v)
    except Exception:
        return None


def normalize_employees(raw_value):
    if not raw_value:
        return []
    if isinstance(raw_value, list):
        return [e for e in raw_value if e]

    txt = str(raw_value)
    txt = txt.replace("\n", ",")
    parts = [p.strip() for p in txt.split(",")]
    seen = set()
    out = []
    for p in parts:
        if p and p not in seen:
            seen.add(p)
            out.append(p)
    return out


def ensure_employee_row(doc, employee):
    if not employee:
        return
    for row in (doc.get("employee") or []):
        if row.get("employee") == employee:
            return
    doc.append("employee", {
        "employee": employee,
        "time_in_mins": 0,
        "completed_qty": 0,
    })


def append_time_log(doc, employee, from_time=None, to_time=None, completed_qty=0):
    if not employee:
        frappe.throw("Employee is required.")

    from_dt = to_datetime(from_time) or frappe.utils.now_datetime()
    to_dt = to_datetime(to_time) if to_time else None

    if to_dt and to_dt < from_dt:
        to_dt = from_dt

    time_in_mins = 0
    if to_dt:
        time_in_mins = max(0, ((to_dt - from_dt).total_seconds() / 60.0))

    doc.append("time_logs", {
        "employee": employee,
        "from_time": from_dt,
        "to_time": to_dt,
        "time_in_mins": time_in_mins,
        "completed_qty": to_float(completed_qty),
    })


def apply_control_action(action_name, payload):
    job_card_name = (payload.get("job_card") or "").strip()
    employee = (payload.get("employee") or "").strip()
    from_time = payload.get("from_time")
    to_time = payload.get("to_time")
    completed_qty = to_float(payload.get("completed_qty"))

    if not job_card_name:
        frappe.throw("Job Card is required.")
    if not employee:
        frappe.throw("Employee is required.")

    doc = frappe.get_doc("Job Card", job_card_name)

    if (doc.get("status") or "").lower() in ("cancelled",):
        frappe.throw("Cancelled Job Card cannot be updated.")

    ensure_employee_row(doc, employee)

    if action_name == "start_job_card":
        append_time_log(doc, employee, from_time=from_time, to_time=None, completed_qty=0)
        doc.status = "Work In Progress"
        if doc.meta.has_field("job_started"):
            doc.job_started = 1
        if doc.meta.has_field("started_time"):
            doc.started_time = to_datetime(from_time) or frappe.utils.now_datetime()

    elif action_name == "update_production":
        if completed_qty <= 0:
            frappe.throw("Completed Qty must be greater than 0 for partial production.")
        append_time_log(doc, employee, from_time=from_time, to_time=to_time, completed_qty=completed_qty)
        if (doc.get("status") or "") in ("Open", "Pending", "Material Transferred"):
            doc.status = "Work In Progress"

    elif action_name == "complete_job_card":
        if completed_qty < 0:
            frappe.throw("Completed Qty cannot be negative.")
        append_time_log(doc, employee, from_time=from_time, to_time=to_time, completed_qty=completed_qty)
        doc.status = "Completed"
        if doc.meta.has_field("actual_end_date"):
            doc.actual_end_date = to_datetime(to_time) or frappe.utils.now_datetime()

    doc.save(ignore_permissions=True)
    return {
        "job_card": doc.name,
        "status": doc.status,
        "total_completed_qty": doc.get("total_completed_qty") or 0,
    }


def build_sales_order_summary(sales_order_name):
    if not sales_order_name:
        frappe.throw("Sales Order is required.")

    so_doc = frappe.get_all(
        "Sales Order",
        filters={"name": sales_order_name},
        fields=["name", "transaction_date", "customer", "status", "delivery_status", "company"],
        limit_page_length=1,
    )
    so = so_doc[0] if so_doc else {"name": sales_order_name}

    so_items = frappe.get_all(
        "Sales Order Item",
        filters={"parent": sales_order_name, "parenttype": "Sales Order"},
        fields=["item_code", "item_name", "qty"],
        limit_page_length=10000,
    )

    work_orders = frappe.get_all(
        "Work Order",
        filters={"sales_order": sales_order_name},
        fields=[
            "name", "production_item", "item_name", "qty", "produced_qty", "status", "production_plan"
        ],
        order_by="name asc",
        limit_page_length=10000,
    )
    return build_summary_from_work_orders(
        work_orders=work_orders,
        entity_type="Sales Order",
        entity_doc=so,
        sales_order_items=so_items,
    )


def build_summary_from_work_orders(work_orders, entity_type, entity_doc, sales_order_items=None):
    wo_names = [w.get("name") for w in work_orders if w.get("name")]

    job_cards = []
    if wo_names:
        job_cards = frappe.get_all(
            "Job Card",
            filters={"work_order": ["in", wo_names]},
            fields=["name", "work_order", "operation", "status", "for_quantity", "total_completed_qty", "bom_no", "item_name", "production_item"],
            order_by="name asc",
            limit_page_length=20000,
        )

    bom_names = list(set([j.get("bom_no") for j in job_cards if j.get("bom_no")]))
    bom_items = []
    if bom_names:
        bom_items = frappe.get_all(
            "BOM Item",
            filters={"parent": ["in", bom_names], "parenttype": "BOM"},
            fields=["parent", "item_code", "item_name", "qty", "uom", "stock_qty"],
            order_by="parent asc, idx asc",
            limit_page_length=50000,
        )

    jc_names = [j.get("name") for j in job_cards if j.get("name")]
    time_logs = []
    if jc_names:
        time_logs = frappe.get_all(
            "Job Card Time Log",
            filters={"parent": ["in", jc_names], "parenttype": "Job Card"},
            fields=["parent", "employee", "completed_qty", "to_time"],
            limit_page_length=50000,
        )

    logs_by_jc = {}
    for t in time_logs:
        p = t.get("parent")
        if not p:
            continue
        if p not in logs_by_jc:
            logs_by_jc[p] = []
        logs_by_jc[p].append(t)

    total_qty = sum([to_float(w.get("qty")) for w in work_orders])
    completed_qty = sum([to_float(w.get("produced_qty")) for w in work_orders])
    remaining_qty = max(total_qty - completed_qty, 0)

    in_process_statuses = ["work in progress", "open", "pending", "material transferred"]
    employee_map = {}

    def add_emp(emp, comp=0, inp=0):
        key = emp or "(No Employee)"
        if key not in employee_map:
            employee_map[key] = {"employee": key, "completed_qty": 0.0, "in_process_qty": 0.0}
        current_completed = to_float(employee_map[key].get("completed_qty"))
        current_in_process = to_float(employee_map[key].get("in_process_qty"))
        employee_map[key]["completed_qty"] = current_completed + to_float(comp)
        employee_map[key]["in_process_qty"] = current_in_process + to_float(inp)

    for t in time_logs:
        add_emp(t.get("employee"), comp=t.get("completed_qty") or 0, inp=0)

    for jc in job_cards:
        st = (jc.get("status") or "").strip().lower()
        if st not in in_process_statuses:
            continue
        jc_qty = to_float(jc.get("total_completed_qty"))
        jc_logs = logs_by_jc.get(jc.get("name"), [])
        jc_employees = list(set([l.get("employee") for l in jc_logs if l.get("employee")]))
        if jc_employees:
            split_qty = jc_qty / len(jc_employees) if len(jc_employees) else 0
            for emp in jc_employees:
                add_emp(emp, comp=0, inp=split_qty)
        else:
            add_emp("(No Employee)", comp=0, inp=jc_qty)

    pp_set = sorted(list(set([w.get("production_plan") for w in work_orders if w.get("production_plan")])))
    so_set = sorted(list(set([w.get("sales_order") for w in work_orders if w.get("sales_order")])))

    jc_total = len(job_cards)
    jc_completed = len([j for j in job_cards if (j.get("status") or "").strip().lower() == "completed"])
    jc_in_process = len([j for j in job_cards if (j.get("status") or "").strip().lower() in in_process_statuses])

    return {
        "entity_type": entity_type,
        "entity_doc": entity_doc,
        "sales_order_items": sales_order_items or [],
        "work_orders": work_orders,
        "sales_orders": so_set,
        "production_plans": pp_set,
        "job_cards": job_cards,
        "bom_items": bom_items,
        "totals": {
            "work_order_total_qty": total_qty,
            "work_order_completed_qty": completed_qty,
            "work_order_remaining_qty": remaining_qty,
            "job_card_total": jc_total,
            "job_card_completed": jc_completed,
            "job_card_in_process": jc_in_process,
        },
        "employee_summary": sorted(
            list(employee_map.values()),
            key=lambda x: (x.get("employee") or "")
        )
    }


def build_production_plan_summary(production_plan_name):
    if not production_plan_name:
        frappe.throw("Production Plan is required.")

    pp_doc = frappe.get_all(
        "Production Plan",
        filters={"name": production_plan_name},
        fields=["name", "posting_date", "status", "company"],
        limit_page_length=1,
    )
    pp = pp_doc[0] if pp_doc else {"name": production_plan_name}

    work_orders = frappe.get_all(
        "Work Order",
        filters={"production_plan": production_plan_name},
        fields=[
            "name", "production_item", "item_name", "qty", "produced_qty", "status",
            "production_plan", "sales_order"
        ],
        order_by="name asc",
        limit_page_length=10000,
    )

    return build_summary_from_work_orders(
        work_orders=work_orders,
        entity_type="Production Plan",
        entity_doc=pp,
        sales_order_items=[],
    )


def build_work_order_summary(work_order_name):
    if not work_order_name:
        frappe.throw("Work Order is required.")

    wo_doc = frappe.get_all(
        "Work Order",
        filters={"name": work_order_name},
        fields=[
            "name", "production_item", "item_name", "qty", "produced_qty", "status",
            "production_plan", "sales_order", "planned_start_date", "planned_end_date"
        ],
        limit_page_length=1,
    )
    wo = wo_doc[0] if wo_doc else {"name": work_order_name}

    work_orders = [wo] if wo.get("name") else []
    return build_summary_from_work_orders(
        work_orders=work_orders,
        entity_type="Work Order",
        entity_doc=wo,
        sales_order_items=[],
    )


def build_sales_order_pipeline(filters):
    so_filters = {}
    if filters.get("company"):
        so_filters["company"] = filters.get("company")
    if filters.get("customer"):
        so_filters["customer"] = filters.get("customer")
    if filters.get("sales_order"):
        so_filters["name"] = filters.get("sales_order")
    if filters.get("so_status"):
        so_filters["status"] = filters.get("so_status")
    if filters.get("from_date") and filters.get("to_date"):
        so_filters["transaction_date"] = ["between", [filters.get("from_date"), filters.get("to_date")]]

    sales_orders = frappe.get_all(
        "Sales Order",
        filters=so_filters,
        fields=["name", "transaction_date", "customer", "status", "delivery_status", "billing_status", "company"],
        order_by="transaction_date desc, name desc",
        limit_page_length=50000,
    )

    so_names = [s.get("name") for s in sales_orders if s.get("name")]
    if not so_names:
        return []

    work_orders = frappe.get_all(
        "Work Order",
        filters={"sales_order": ["in", so_names]},
        fields=["name", "sales_order", "production_plan", "status", "qty", "produced_qty"],
        limit_page_length=100000,
    )
    wo_names = [w.get("name") for w in work_orders if w.get("name")]

    job_cards = []
    if wo_names:
        job_cards = frappe.get_all(
            "Job Card",
            filters={"work_order": ["in", wo_names]},
            fields=["name", "work_order", "status", "operation"],
            limit_page_length=200000,
        )

    stock_entries = []
    if wo_names:
        stock_entries = frappe.get_all(
            "Stock Entry",
            filters={"work_order": ["in", wo_names], "docstatus": ["!=", 2]},
            fields=["name", "work_order", "stock_entry_type", "docstatus"],
            limit_page_length=200000,
        )

    wo_by_so = {}
    for w in work_orders:
        so = w.get("sales_order")
        if not so:
            continue
        if so not in wo_by_so:
            wo_by_so[so] = []
        wo_by_so[so].append(w)

    jc_by_wo = {}
    for jc in job_cards:
        wo = jc.get("work_order")
        if not wo:
            continue
        if wo not in jc_by_wo:
            jc_by_wo[wo] = []
        jc_by_wo[wo].append(jc)

    se_by_wo = {}
    for se in stock_entries:
        wo = se.get("work_order")
        if not wo:
            continue
        if wo not in se_by_wo:
            se_by_wo[wo] = []
        se_by_wo[wo].append(se)

    rows = []
    for so in sales_orders:
        so_name = so.get("name")
        wos = wo_by_so.get(so_name, [])
        pp_set = sorted(list(set([w.get("production_plan") for w in wos if w.get("production_plan")])))

        wo_total = len(wos)
        wo_completed = len([w for w in wos if (w.get("status") or "").strip().lower() == "completed"])
        wo_qty_total = sum([to_float(w.get("qty")) for w in wos])
        wo_qty_done = sum([to_float(w.get("produced_qty")) for w in wos])
        wo_completion_pct = 0
        if wo_qty_total > 0:
            wo_completion_pct = (wo_qty_done / wo_qty_total) * 100

        jc_total = 0
        jc_completed = 0
        se_count = 0
        wo_details = []
        jc_details = []
        for w in wos:
            wo_name = w.get("name")
            jc_list = jc_by_wo.get(wo_name, [])
            se_list = se_by_wo.get(wo_name, [])
            jc_total += len(jc_list)
            jc_completed += len([j for j in jc_list if (j.get("status") or "").strip().lower() == "completed"])
            se_count += len(se_list)
            wo_qty = to_float(w.get("qty"))
            wo_done = to_float(w.get("produced_qty"))
            wo_pct = 0
            if wo_qty > 0:
                wo_pct = (wo_done / wo_qty) * 100
            wo_details.append({
                "name": wo_name,
                "status": w.get("status"),
                "qty": wo_qty,
                "produced_qty": wo_done,
                "completion_pct": round(wo_pct, 2),
            })
            for j in jc_list:
                jc_details.append({
                    "name": j.get("name"),
                    "work_order": wo_name,
                    "status": j.get("status"),
                    "operation": j.get("operation"),
                })

        rows.append({
            "sales_order": so_name,
            "date": so.get("transaction_date"),
            "customer": so.get("customer"),
            "so_status": so.get("status"),
            "delivery_status": so.get("delivery_status"),
            "billing_status": so.get("billing_status"),
            "production_plans": ", ".join(pp_set),
            "work_order_total": wo_total,
            "work_order_completed": wo_completed,
            "job_card_total": jc_total,
            "job_card_completed": jc_completed,
            "stock_entry_count": se_count,
            "wo_completion_pct": round(wo_completion_pct, 2),
            "wo_details": wo_details,
            "jc_details": jc_details,
        })

    return rows


if action in ("start_job_card", "update_production", "complete_job_card"):
    employees = normalize_employees(args.get("employees"))
    if not employees:
        employees = normalize_employees(args.get("employee"))

    if not employees:
        frappe.throw("At least one employee is required.")

    total_completed_qty = to_float(args.get("completed_qty"))
    split_qty = 0
    if action in ("update_production", "complete_job_card") and len(employees) > 0:
        split_qty = total_completed_qty / len(employees)

    results = []
    for idx, emp in enumerate(employees):
        emp_qty = 0
        if action in ("update_production", "complete_job_card"):
            if idx == len(employees) - 1:
                emp_qty = total_completed_qty - (split_qty * idx)
            else:
                emp_qty = split_qty

        payload = {
            "job_card": args.get("job_card"),
            "employee": emp,
            "from_time": args.get("from_time"),
            "to_time": args.get("to_time"),
            "completed_qty": emp_qty,
        }
        results.append(apply_control_action(action, payload))

    frappe.db.commit()
    frappe.response["message"] = {
        "ok": True,
        "action": action,
        "job_card": args.get("job_card"),
        "employees": employees,
        "results": results,
        "timestamp": frappe.utils.now(),
    }

elif action == "sales_order_summary":
    sales_order_name = (args.get("sales_order") or "").strip()
    summary = build_sales_order_summary(sales_order_name)
    frappe.response["message"] = {
        "ok": True,
        "action": action,
        "summary": summary,
        "timestamp": frappe.utils.now(),
    }

elif action == "smart_summary":
    sales_order_name = (args.get("sales_order") or "").strip()
    production_plan_name = (args.get("production_plan") or "").strip()
    work_order_name = (args.get("work_order") or "").strip()

    summary = None
    source = ""
    if sales_order_name:
        summary = build_sales_order_summary(sales_order_name)
        source = "Sales Order"
    elif production_plan_name:
        summary = build_production_plan_summary(production_plan_name)
        source = "Production Plan"
    elif work_order_name:
        summary = build_work_order_summary(work_order_name)
        source = "Work Order"
    else:
        frappe.throw("Provide sales_order or production_plan or work_order for smart summary.")

    frappe.response["message"] = {
        "ok": True,
        "action": action,
        "source": source,
        "summary": summary,
        "timestamp": frappe.utils.now(),
    }

elif action == "sales_order_pipeline":
    filters = {
        "company": (args.get("company") or "").strip(),
        "customer": (args.get("customer") or "").strip(),
        "sales_order": (args.get("sales_order") or "").strip(),
        "from_date": args.get("from_date"),
        "to_date": args.get("to_date"),
        "so_status": (args.get("so_status") or "").strip(),
    }
    rows = build_sales_order_pipeline(filters)
    frappe.response["message"] = {
        "ok": True,
        "action": action,
        "rows": rows,
        "count": len(rows),
        "timestamp": frappe.utils.now(),
    }

else:
    from_date = args.get("from_date")
    to_date = args.get("to_date")
    company = args.get("company")
    status = args.get("status")
    workstation = args.get("workstation")
    operation = args.get("operation")
    work_order = args.get("work_order")
    job_card = args.get("job_card")
    sales_order = args.get("sales_order")

    # Build filters for Job Cards
    job_card_filters = {}

    if status:
        job_card_filters["status"] = status
    else:
        # Default: show active job cards
        job_card_filters["status"] = ["in", ["Work In Progress", "Open", "Pending", "Material Transferred"]]

    if from_date and to_date:
        job_card_filters["posting_date"] = ["between", [from_date, to_date]]
    if company:
        job_card_filters["company"] = company
    if workstation:
        job_card_filters["workstation"] = workstation
    if operation:
        job_card_filters["operation"] = operation
    if job_card:
        job_card_filters["name"] = job_card

    if work_order:
        job_card_filters["work_order"] = work_order
    elif sales_order:
        so_wo_rows = frappe.get_all(
            "Work Order",
            filters={"sales_order": sales_order},
            fields=["name"],
            limit_page_length=10000,
        )
        so_wo_names = [r.get("name") for r in so_wo_rows if r.get("name")]
        if so_wo_names:
            job_card_filters["work_order"] = ["in", so_wo_names]
        else:
            job_card_filters["work_order"] = ["in", ["__no_work_order__"]]

    # Fetch job cards
    job_cards = frappe.get_all(
        "Job Card",
        filters=job_card_filters,
        fields=[
            "name", "work_order", "production_item", "item_name", "for_quantity",
            "total_completed_qty", "process_loss_qty", "operation", "workstation",
            "workstation_type", "posting_date", "status", "company",
            "expected_start_date", "expected_end_date", "actual_start_date",
            "actual_end_date", "time_required", "total_time_in_mins", "docstatus"
        ],
        order_by="actual_start_date desc, posting_date desc, name desc",
        limit_page_length=10000,
    )

    # Get work order names
    wo_names = list(set([jc.get("work_order") for jc in job_cards if jc.get("work_order")]))

    # Fetch work orders for additional info + links
    wo_map = {}
    if wo_names:
        work_orders = frappe.get_all(
            "Work Order",
            filters={"name": ["in", wo_names]},
            fields=[
                "name", "production_item", "item_name", "qty", "produced_qty", "status",
                "sales_order", "production_plan"
            ],
            limit_page_length=10000,
        )
        wo_map = {wo.get("name"): wo for wo in work_orders if wo.get("name")}

    # Get job card names
    jc_names = [jc.get("name") for jc in job_cards if jc.get("name")]

    # Fetch time logs to get actual start times
    employee_time_logs = []
    if jc_names:
        def chunks_list(lst, n=1000):
            for i in range(0, len(lst), n):
                yield lst[i:i+n]

        for chunk in chunks_list(jc_names):
            try:
                time_logs = frappe.get_all(
                    "Job Card Time Log",
                    filters={"parent": ["in", chunk]},
                    fields=[
                        "parent", "from_time", "to_time", "time_in_mins",
                        "employee", "employee_name", "completed_qty", "operation"
                    ],
                    order_by="from_time asc",
                    limit_page_length=50000,
                )
                employee_time_logs.extend(time_logs)
            except Exception:
                pass

    # Group time logs by job card
    time_logs_by_jc = {}
    for tl in employee_time_logs:
        parent = tl.get("parent")
        if parent:
            if parent not in time_logs_by_jc:
                time_logs_by_jc[parent] = []
            time_logs_by_jc[parent].append(tl)

    # Build response with job cards and their operations
    result = []
    for jc in job_cards:
        jc_name = jc.get("name")
        wo_name = jc.get("work_order")
        wo_info = wo_map.get(wo_name, {})

        first_start_time = None
        time_logs = time_logs_by_jc.get(jc_name, [])
        if time_logs:
            sorted_logs = sorted(time_logs, key=lambda x: x.get("from_time") or "")
            first_start_time = sorted_logs[0].get("from_time")

        start_time = jc.get("actual_start_date") or first_start_time

        result.append({
            "job_card": jc_name,
            "work_order": wo_name,
            "operation": jc.get("operation") or "N/A",
            "production_item": jc.get("production_item"),
            "item_name": jc.get("item_name") or jc.get("production_item"),
            "workstation": jc.get("workstation"),
            "status": jc.get("status"),
            "for_quantity": jc.get("for_quantity") or 0,
            "completed_qty": jc.get("total_completed_qty") or 0,
            "start_time": start_time,
            "expected_start_date": jc.get("expected_start_date"),
            "expected_end_date": jc.get("expected_end_date"),
            "actual_end_date": jc.get("actual_end_date"),
            "time_required": jc.get("time_required"),
            "total_time_in_mins": jc.get("total_time_in_mins") or 0,
            "work_order_item": wo_info.get("item_name") or wo_info.get("production_item"),
            "work_order_qty": wo_info.get("qty") or 0,
            "work_order_produced": wo_info.get("produced_qty") or 0,
            "work_order_status": wo_info.get("status"),
            "sales_order": wo_info.get("sales_order") or "",
            "production_plan": wo_info.get("production_plan") or "",
            "posting_date": jc.get("posting_date"),
            "company": jc.get("company") or "",
        })

    status_priority = {
        "Work In Progress": 1,
        "Material Transferred": 2,
        "Open": 3,
        "Pending": 4,
        "Completed": 5,
        "On Hold": 6,
        "Cancelled": 7,
    }

    result.sort(key=lambda x: (
        status_priority.get(x.get("status"), 99),
        x.get("start_time") or "",
        x.get("job_card") or ""
    ))

    frappe.response["message"] = {
        "job_cards": result,
        "count": len(result),
        "timestamp": frappe.utils.now(),
    }

# production_dashboard_api (v3 optimized)
# Script Type: API
# API Method: production_dashboard_api
#
# Key upgrades:
# - Safe caps via limit_* args to protect performance on large ranges
# - Avoid per-document get_doc; batch fetch time logs
# - Return distincts for slicers

args = frappe.form_dict

from_date = args.get("from_date")
to_date = args.get("to_date")
company = args.get("company")
production_item = args.get("production_item")
status = args.get("status")
workstation = args.get("workstation")
sales_order = args.get("sales_order")

# Performance caps (frontend sets defaults; you can adjust here)
limit_work_orders = int(args.get("limit_work_orders") or 15000)
limit_job_cards   = int(args.get("limit_job_cards") or 20000)
limit_time_logs   = int(args.get("limit_time_logs") or 50000)

filters = {}
if from_date and to_date:
    filters["planned_start_date"] = ["between", [from_date, to_date]]
if company:
    filters["company"] = company
if production_item:
    filters["production_item"] = production_item
if status:
    filters["status"] = status
if sales_order:
    filters["sales_order"] = sales_order

work_orders = frappe.get_all(
    "Work Order",
    filters=filters,
    fields=[
        "name","company","status","production_item","item_name",
        "qty","produced_qty","planned_start_date","planned_end_date",
        "actual_start_date","actual_end_date","material_transferred_for_manufacturing",
        "sales_order","production_plan"
    ],
    order_by="planned_start_date asc",
    limit_page_length=limit_work_orders,
)

wo_names = [d.get("name") for d in work_orders if d.get("name")]
wo_map = {wo.get('name'): wo for wo in work_orders if wo.get('name')}

# Sales Orders / Production Plans (real documents only, no synthetic buckets)
sales_order_names = list(set([wo.get("sales_order") for wo in work_orders if wo.get("sales_order")]))
production_plan_names = list(set([wo.get("production_plan") for wo in work_orders if wo.get("production_plan")]))

so_filters = {}
if company:
    so_filters["company"] = company
if from_date and to_date:
    so_filters["transaction_date"] = ["between", [from_date, to_date]]
if sales_order:
    so_filters["name"] = sales_order

sales_orders = frappe.get_all(
    "Sales Order",
    filters=so_filters,
    fields=[
        "name", "transaction_date", "customer", "company", "status",
        "delivery_status", "billing_status", "grand_total"
    ],
    order_by="transaction_date asc, name asc",
    limit_page_length=100000,
)

pp_filters = {}
if company:
    pp_filters["company"] = company
if from_date and to_date:
    pp_filters["posting_date"] = ["between", [from_date, to_date]]

production_plans = frappe.get_all(
    "Production Plan",
    filters=pp_filters,
    fields=["name", "posting_date", "company", "status"],
    order_by="posting_date asc, name asc",
    limit_page_length=100000,
)

# Work Order Operations
operations_by_wo = {}
workstation_set = set()

if wo_names:
    op_filters = {"parent": ["in", wo_names], "parenttype": "Work Order"}
    if workstation:
        op_filters["workstation"] = workstation

    op_rows = frappe.get_all(
        "Work Order Operation",
        filters=op_filters,
        fields=["parent","operation","workstation","time_in_mins","completed_qty","status"],
        limit_page_length=100000,
    )
    for row in op_rows:
        parent = row.pop("parent", None)
        if parent:
            operations_by_wo.setdefault(parent, []).append(row)
            if row.get("workstation"):
                workstation_set.add(row["workstation"])

# If workstation filter applied, keep only WOs that have ops in that workstation
if workstation:
    keep = set([k for k,v in operations_by_wo.items() if v])
    work_orders = [wo for wo in work_orders if wo.get("name") in keep]
    wo_names = [d.get("name") for d in work_orders if d.get("name")]
    wo_map = {wo.get('name'): wo for wo in work_orders if wo.get('name')}

# Job Cards
job_cards = []
all_jc_names = set()

if wo_names:
    jc_filters = {"work_order": ["in", wo_names]}
    if company:
        jc_filters["company"] = company

    jc_by_wo = frappe.get_all(
        "Job Card",
        filters=jc_filters,
        fields=[
            "name", "work_order", "production_item", "item_name", "for_quantity",
            "total_completed_qty", "process_loss_qty", "operation", "workstation",
            "workstation_type", "posting_date", "status", "company",
            "expected_start_date", "expected_end_date", "actual_start_date",
            "actual_end_date", "time_required", "total_time_in_mins", "docstatus"
        ],
        order_by="posting_date asc",
        limit_page_length=limit_job_cards,
    )
    for jc in jc_by_wo:
        if jc.get("name"):
            all_jc_names.add(jc.get("name"))
            job_cards.append(jc)

# Also fetch by posting date range to catch job cards even if WO list is capped
if from_date and to_date:
    jc_filters_by_date = {"posting_date": ["between", [from_date, to_date]]}
    if company:
        jc_filters_by_date["company"] = company

    jc_by_date = frappe.get_all(
        "Job Card",
        filters=jc_filters_by_date,
        fields=[
            "name", "work_order", "production_item", "item_name", "for_quantity",
            "total_completed_qty", "process_loss_qty", "operation", "workstation",
            "workstation_type", "posting_date", "status", "company",
            "expected_start_date", "expected_end_date", "actual_start_date",
            "actual_end_date", "time_required", "total_time_in_mins", "docstatus"
        ],
        order_by="posting_date asc",
        limit_page_length=limit_job_cards,
    )
    for jc in jc_by_date:
        jc_name = jc.get("name")
        if jc_name and jc_name not in all_jc_names:
            all_jc_names.add(jc_name)
            job_cards.append(jc)

job_cards = sorted(job_cards, key=lambda x: (x.get("posting_date") or "", x.get("name") or ""))

# Time logs (batch)
employee_time_logs = []
if job_cards:
    jc_names = [jc.get("name") for jc in job_cards if jc.get("name")]

    def chunks_list(lst, n=1000):
        for i in range(0, len(lst), n):
            yield lst[i:i+n]

    time_log_rows = []
    # Try parentfield + fallback
    for batch in chunks_list(jc_names, 1000):
        rows = frappe.get_all(
            "Job Card Time Log",
            filters={
                "parent": ["in", batch],
                "parenttype": "Job Card",
            },
            fields=["parent", "employee", "from_time", "to_time", "time_in_mins", "completed_qty", "operation"],
            limit_page_length=100000,
        )
        time_log_rows.extend(rows)
        if len(time_log_rows) >= limit_time_logs:
            time_log_rows = time_log_rows[:limit_time_logs]
            break

    jc_to_wo = {jc["name"]: jc.get("work_order") for jc in job_cards if jc.get("name")}
    jc_details_map = {jc["name"]: jc for jc in job_cards if jc.get("name")}

    for log in time_log_rows:
        job_card = log.get("parent")
        work_order = jc_to_wo.get(job_card, "") or ""
        employee = log.get("employee") or "(No Employee)"
        from_time = log.get("from_time")
        to_time = log.get("to_time")
        time_in_mins = float(log.get("time_in_mins") or 0)
        completed_qty = float(log.get("completed_qty") or 0)

        # Skip empty/zero logs in Employee tab:
        # no timestamps AND both metrics are zero.
        if (not from_time and not to_time and time_in_mins == 0 and completed_qty == 0):
            continue

        jc_details = jc_details_map.get(job_card, {}) or {}
        wo_details = wo_map.get(work_order, {}) if work_order else {}

        employee_time_logs.append({
            "work_order": work_order,
            "job_card": job_card,
            "employee": employee,
            "from_time": from_time,
            "to_time": to_time,
            "time_in_mins": time_in_mins,
            "completed_qty": completed_qty,
            "operation": log.get("operation") or jc_details.get("operation") or "",
            "production_item": wo_details.get("production_item") or jc_details.get("production_item") or "",
            "item_name": wo_details.get("item_name") or jc_details.get("item_name") or "",
            "company": wo_details.get("company") or jc_details.get("company") or "",
        })

# Distinct values for slicers
company_set = set()
prod_item_set = set()
status_set = set()
employee_set = set()

for wo in work_orders:
    if wo.get("company"): company_set.add(wo["company"])
    if wo.get("production_item"): prod_item_set.add(wo["production_item"])
    if wo.get("status"): status_set.add(wo["status"])

for jc in job_cards:
    if jc.get("company"): company_set.add(jc["company"])
    if jc.get("production_item"): prod_item_set.add(jc["production_item"])
    if jc.get("status"): status_set.add(jc["status"])
    if jc.get("workstation"): workstation_set.add(jc["workstation"])

for log in employee_time_logs:
    emp = log.get("employee")
    if emp and emp != "(No Employee)":
        employee_set.add(emp)

distinct_values = {
    "companies": sorted(company_set),
    "production_items": sorted(prod_item_set),
    "statuses": sorted(status_set),
    "workstations": sorted(workstation_set),
    "employees": sorted(employee_set),
    "sales_orders": sorted(list(set([so.get("name") for so in sales_orders if so.get("name")]))),
    "production_plans": sorted(list(set([pp.get("name") for pp in production_plans if pp.get("name")]))),
}

response_data = {
    "work_orders": work_orders,
    "operations_by_wo": operations_by_wo,
    "job_cards": job_cards,
    "employee_time_logs": employee_time_logs,
    "sales_orders": sales_orders,
    "production_plans": production_plans,
    "distinct_values": distinct_values,
    "debug": {
        "caps": {
            "limit_work_orders": limit_work_orders,
            "limit_job_cards": limit_job_cards,
            "limit_time_logs": limit_time_logs,
        },
        "counts": {
            "work_orders": len(work_orders),
            "job_cards": len(job_cards),
            "employee_time_logs": len(employee_time_logs),
        }
    }
}

frappe.response["message"] = response_data
